import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler);

const formatCurrency = (value) => {
  if (value == null) return "N/A";
  return `₹${Number(value).toLocaleString("en-IN")}`;
};

const formatNumber = (value, decimals = 2) => {
  if (value == null) return "N/A";
  return Number(value).toFixed(decimals);
};

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchData = async () => {
    setError("");
    setLoading(true);
    setData(null);

    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch stock data.");
    } finally {
      setLoading(false);
    }
  };

  const renderMetric = (label, value, isCurrency = false) => (
    <li key={label}>
      <strong>{label}:</strong>{" "}
      {isCurrency ? formatCurrency(value) : formatNumber(value)}
    </li>
  );

  const renderChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map((d) =>
      new Date(d.date).toLocaleDateString("en-IN", { month: "short", day: "numeric" })
    );
    const prices = data.historical.map((d) => d.close);

    return (
      <Line
        data={{
          labels,
          datasets: [
            {
              label: `${data.symbol} Closing Price`,
              data: prices,
              borderColor: "#007bff",
              backgroundColor: "rgba(0, 123, 255, 0.1)",
              tension: 0.3,
              fill: true,
            },
          ],
        }}
        options={{
          responsive: true,
          plugins: {
            legend: { display: false },
            tooltip: {
              callbacks: {
                label: (ctx) => `₹${ctx.parsed.y}`,
              },
            },
          },
          scales: {
            y: {
              ticks: {
                callback: (value) => `₹${value}`,
              },
            },
          },
        }}
      />
    );
  };

  const metricList = [
    { label: "EPS", key: "eps" },
    { label: "ROE (%)", key: "roe" },
    { label: "Book Value", key: "bookValue", currency: true },
    { label: "Face Value", key: "faceValue", currency: true },
    { label: "PE Ratio", key: "peRatio" },
    { label: "Dividend Yield (%)", key: "dividendYield" },
    { label: "ROCE (%)", key: "roce" },
    { label: "Market Cap", key: "marketCap", currency: true },
    { label: "52 Week High", key: "fiftyTwoWeekHigh", currency: true },
    { label: "52 Week Low", key: "fiftyTwoWeekLow", currency: true },
  ];

  const renderList = (arr, emptyMsg) =>
    arr && arr.length > 0 ? (
      <ul>
        {arr.map((item, i) => (
          <li key={i}>{item}</li>
        ))}
      </ul>
    ) : (
      <p style={{ color: "gray" }}>{emptyMsg}</p>
    );

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>📈 Indian Stock Details</h2>
      <div style={{ marginBottom: "10px" }}>
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter Symbol (e.g., TCS.NS)"
          style={{
            padding: "8px",
            width: "250px",
            marginRight: "10px",
            borderRadius: "4px",
            border: "1px solid #ccc",
          }}
        />
        <button
          onClick={fetchData}
          disabled={loading}
          style={{
            padding: "8px 16px",
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          {loading ? "Loading..." : "Get Details"}
        </button>
      </div>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <>
          <h3>{data.name} ({data.symbol})</h3>
          <h1 style={{ color: data.change > 0 ? "green" : "red" }}>
            ₹{formatNumber(data.price)} | Change: {formatNumber(data.change)} ({formatNumber(data.percentChange)}%)
          </h1>

          <h4>📌 Key Metrics</h4>
          <ul>
            {metricList.map((metric) =>
              renderMetric(metric.label, data[metric.key], metric.currency)
            )}
          </ul>

          {renderChart()}

          <h4>👨‍👩‍👧‍👦 Peers</h4>
          {renderList(data.peers, "No peer data available.")}

          <h4>✅ Pros</h4>
          {renderList(data.pros, "No pros found.")}

          <h4>❌ Cons</h4>
          {renderList(data.cons, "No cons found.")}

          <h4>📄 Balance Sheet</h4>
          {data.balanceSheet?.length > 0 ? (
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                marginBottom: "20px",
                border: "1px solid #ccc",
              }}
            >
              <thead style={{ backgroundColor: "#007bff", color: "#fff" }}>
                <tr>
                  <th style={{ padding: "8px" }}>Year</th>
                  <th style={{ padding: "8px" }}>Total Assets</th>
                  <th style={{ padding: "8px" }}>Total Liabilities</th>
                  <th style={{ padding: "8px" }}>Equity</th>
                </tr>
              </thead>
              <tbody>
                {data.balanceSheet.map((item, i) => (
                  <tr key={i} style={{ background: i % 2 === 0 ? "#f9f9f9" : "#fff" }}>
                    <td style={{ padding: "8px" }}>{item.year}</td>
                    <td style={{ padding: "8px" }}>{formatCurrency(item.assets)}</td>
                    <td style={{ padding: "8px" }}>{formatCurrency(item.liabilities)}</td>
                    <td style={{ padding: "8px" }}>{formatCurrency(item.equity)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p>No balance sheet data.</p>
          )}

          <h4>📄 Profit & Loss</h4>
          {data.profitLoss?.length > 0 ? (
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                marginBottom: "20px",
                border: "1px solid #ccc",
              }}
            >
              <thead style={{ backgroundColor: "#28a745", color: "#fff" }}>
                <tr>
                  <th style={{ padding: "8px" }}>Year</th>
                  <th style={{ padding: "8px" }}>Revenue</th>
                  <th style={{ padding: "8px" }}>Profit</th>
                </tr>
              </thead>
              <tbody>
                {data.profitLoss.map((item, i) => (
                  <tr key={i} style={{ background: i % 2 === 0 ? "#f9f9f9" : "#fff" }}>
                    <td style={{ padding: "8px" }}>{item.year}</td>
                    <td style={{ padding: "8px" }}>{formatCurrency(item.revenue)}</td>
                    <td style={{ padding: "8px" }}>{formatCurrency(item.profit)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p>No profit & loss data.</p>
          )}
        </>
      )}
    </div>
  );
};

export default IndianStockDetails;
